class BLEIoTDevice:
    """BLE GATT Server for IoT device control and monitoring."""

    DEVICE_NAME = "ESP32-IoT-Device"
    FIRMWARE_VERSION = "1.0.0"

    def __init__(self):
        self._ble = bluetooth.BLE()
        self._ble.active(True)
        self._ble.irq(self._irq_handler)

